### Step 6: Implement `deriveStructuralVariantBinding` (Scala 3 Only)

**File:** `schema/shared/src/main/scala-3/zio/blocks/schema/binding/BindingCompanionVersionSpecific.scala`

**Location:** Add a new branch in `deriveBinding` BEFORE the existing `isUnion` check:

```scala
else if (isUnion(tpe) && isOneOfStructuralUnion(tpe)) deriveStructuralVariantBinding[A](tpe)
else if (isUnion(tpe)) deriveUnionBinding[A](tpe)
```

**OneOf detection:**
```scala
private case class OneOfAlternative(discriminatorName: String, payloadTpe: TypeRepr, caseTpe: TypeRepr)

private def isOneOfStructuralUnion(tpe: TypeRepr): Boolean = {
  val subtypes = allUnionTypes(tpe)
  subtypes.forall { st =>
    isStructuralType(st) && {
      val fields = extractStructuralFields(st)
      fields.size == 1  // Each alternative has exactly one field (the discriminator)
    }
  }
}

private def extractOneOfAlternatives(tpe: TypeRepr): List[OneOfAlternative] = {
  allUnionTypes(tpe).map { st =>
    val fields = extractStructuralFields(st)
    if (fields.size != 1)
      fail(s"OneOf structural union requires each alternative to have exactly one field. Found: ${fields.map(_.name).mkString(", ")}")
    OneOfAlternative(fields.head.name, fields.head.tpe, st)
  }
}
```

**Variant binding implementation:**
- **Discriminator:** Uses reflection to check which method exists on the runtime value
- **Matchers:** Each matcher tries `getClass.getMethod(discriminatorName)` and returns the value or null

```scala
private def deriveStructuralVariantBinding[A: Type](tpe: TypeRepr)(using Quotes): Expr[Any] = {
  ensureStructuralSupported(tpe)

  val alternatives = extractOneOfAlternatives(tpe)

  // Validate unique discriminator names
  val names = alternatives.map(_.discriminatorName)
  if (names.distinct.size != names.size)
    fail(s"OneOf structural union has duplicate discriminator names: ${names.mkString(", ")}")

  // Generate discriminator
  val discriminatorExpr = '{ 
    new Discriminator[A] {
      def discriminate(a: A): Int = {
        val clazz = a.asInstanceOf[AnyRef].getClass
        ${
          val cases = alternatives.zipWithIndex.map { case (alt, idx) =>
            val nameExpr = Expr(alt.discriminatorName)
            val idxExpr = Expr(idx)
            '{ 
              try { clazz.getMethod($nameExpr); $idxExpr }
              catch { case _: NoSuchMethodException => -1 }
            }
          }
          // Find first non-negative result
          cases.reduce((a, b) => '{ val r = $a; if (r >= 0) r else $b })
        }
      }
    }
  }

  // Generate matchers
  val matcherExprs = alternatives.map { alt =>
    alt.caseTpe.asType match {
      case '[ct] =>
        val nameExpr = Expr(alt.discriminatorName)
        '{
          new Matcher[ct] {
            def downcastOrNull(a: Any): ct = {
              try {
                a.asInstanceOf[AnyRef].getClass.getMethod($nameExpr)
                a.asInstanceOf[ct]
              } catch {
                case _: NoSuchMethodException => null.asInstanceOf[ct]
              }
            }
          }
        }.asInstanceOf[Expr[Matcher[? <: A]]]
    }
  }

  val matchersExpr = Varargs(matcherExprs)

  '{
    new Binding.Variant[A](
      discriminator = $discriminatorExpr,
      matchers = Matchers($matchersExpr*)
    )
  }
}
```

