### Step 7: Scala 2 Implementation

**File:** `schema/shared/src/main/scala-2/zio/blocks/schema/binding/BindingCompanionVersionSpecific.scala`

Scala 2 has `RefinedType` instead of `Refinement`. No union types (`|`) or intersection types (`&`).

**7a. Add detection and extraction:**
```scala
private def isStructuralType(tpe: Type): Boolean = tpe.dealias match {
  case RefinedType(_, _) => true
  case _                 => false
}

private case class StructField(name: String, tpe: Type)

private def extractStructuralFields(tpe: Type): List[StructField] = tpe.dealias match {
  case RefinedType(parents, scope) =>
    scope.toList.collect {
      case m: MethodSymbol if m.isAbstract && m.paramLists.flatten.isEmpty =>
        StructField(m.name.decodedName.toString, m.returnType.asSeenFrom(tpe, m.owner))
    }.sortBy(_.name)
  case _ => Nil
}

private def ensureStructuralSupported(tpe: Type): Unit =
  if (!zio.blocks.schema.Platform.supportsReflection)
    c.abort(c.enclosingPosition, 
      s"Cannot derive Binding for structural type $tpe on ${zio.blocks.schema.Platform.name}. " +
      "Structural types require reflection APIs which are only available on JVM.")
```

**7b. Add branch in `deriveBinding`:**
```scala
else if (isStructuralType(tpe)) deriveStructuralRecordBinding(tpe)
else if (isNonAbstractScalaClass(tpe)) {
  // existing...
}
```

**7c. Implement `deriveStructuralRecordBinding` using quasiquotes:**

Scala 2 can use quasiquotes to generate anonymous classes more easily:
```scala
private def deriveStructuralRecordBinding(tpe: Type): c.Expr[Any] = {
  ensureStructuralSupported(tpe)

  val fields = extractStructuralFields(tpe)
  if (fields.isEmpty)
    fail(s"Cannot derive Binding for empty structural type $tpe")

  // Compute registers (same pattern as Scala 3)
  // ...

  // Generate constructor body using quasiquotes
  val constructBody = fields.zipWithIndex.map { case (f, i) =>
    val valName = TermName(s"_${f.name}")
    val getter = registerGetter(f, i) // generates in.getInt(...) etc.
    q"val $valName = $getter"
  }

  val anonMembers = fields.map { f =>
    val valName = TermName(s"_${f.name}")
    val methodName = TermName(f.name)
    q"def $methodName: ${f.tpe} = $valName"
  }

  val construct = q"""
    ..$constructBody
    (new { ..$anonMembers }).asInstanceOf[$tpe]
  """

  // Generate deconstructor using reflection
  val deconstructBody = fields.zipWithIndex.map { case (f, i) =>
    val nameStr = f.name
    registerSetter(f, i, q"""in.getClass.getMethod($nameStr).invoke(in)""")
  }

  c.Expr[Any](q"""
    new _root_.zio.blocks.schema.binding.Binding.Record[$tpe](
      constructor = new _root_.zio.blocks.schema.binding.Constructor[$tpe] {
        def usedRegisters: _root_.zio.blocks.schema.binding.RegisterOffset.RegisterOffset = $usedRegistersExpr
        def construct(in: _root_.zio.blocks.schema.binding.Registers, 
                      offset: _root_.zio.blocks.schema.binding.RegisterOffset.RegisterOffset): $tpe = {
          $construct
        }
      },
      deconstructor = new _root_.zio.blocks.schema.binding.Deconstructor[$tpe] {
        def usedRegisters: _root_.zio.blocks.schema.binding.RegisterOffset.RegisterOffset = $usedRegistersExpr
        def deconstruct(out: _root_.zio.blocks.schema.binding.Registers,
                        offset: _root_.zio.blocks.schema.binding.RegisterOffset.RegisterOffset,
                        in: $tpe): Unit = {
          ..$deconstructBody
        }
      }
    )
  """)
}
```

