### 3. Data Model Completeness Tests

Verify that round-tripping through the model preserves type information.
```scala
test("TypeRepr substitution is correct") {
  val A = TypeParam("A", 0)
  val listOfA = TypeRepr.Applied(TypeRepr.Ref(listId), List(TypeRepr.ParamRef(A)))
  val substituted = listOfA.substitute(Map(A -> TypeRepr.Ref(intId)))
  assertTrue(substituted == TypeRepr.Applied(TypeRepr.Ref(listId), List(TypeRepr.Ref(intId))))
}

test("normalization expands aliases") {
  type MyInt = Int
  val myIntRepr = TypeRepr.Ref(TypeId.of[MyInt])
  val normalized = TypeNormalization.normalize(myIntRepr)
  assertTrue(normalized == TypeRepr.Ref(TypeId.of[Int]))
}
```

### 4. Subtyping Tests

Verify that `isSubtypeOf` correctly implements Scala's subtyping rules.

#### Basic Subtyping
```scala
test("Nothing is subtype of everything") {
  assertTrue(TypeId.of[Nothing].isSubtypeOf(TypeId.of[Int]))
  assertTrue(TypeId.of[Nothing].isSubtypeOf(TypeId.of[String]))
  assertTrue(TypeId.of[Nothing].isSubtypeOf(TypeId.of[Any]))
}

test("everything is subtype of Any") {
  assertTrue(TypeId.of[Int].isSubtypeOf(TypeId.of[Any]))
  assertTrue(TypeId.of[String].isSubtypeOf(TypeId.of[Any]))
  assertTrue(TypeId.of[List[Int]].isSubtypeOf(TypeId.of[Any]))
}

test("reflexivity") {
  assertTrue(TypeId.of[String].isSubtypeOf(TypeId.of[String]))
  assertTrue(TypeId.of[List[Int]].isSubtypeOf(TypeId.of[List[Int]]))
}
```

#### Variance-Aware Subtyping
```scala
test("covariant type parameter subtyping") {
  // List is covariant: List[Dog] <: List[Animal]
  assertTrue(TypeId.of[List[Dog]].isSubtypeOf(TypeId.of[List[Animal]]))
  assertTrue(!TypeId.of[List[Animal]].isSubtypeOf(TypeId.of[List[Dog]]))
}

test("contravariant type parameter subtyping") {
  // Function1 is contravariant in input: (Animal => Int) <: (Dog => Int)
  assertTrue(TypeId.of[Animal => Int].isSubtypeOf(TypeId.of[Dog => Int]))
  assertTrue(!TypeId.of[Dog => Int].isSubtypeOf(TypeId.of[Animal => Int]))
}

test("invariant type parameter subtyping") {
  // Array is invariant
  assertTrue(!TypeId.of[Array[Dog]].isSubtypeOf(TypeId.of[Array[Animal]]))
  assertTrue(!TypeId.of[Array[Animal]].isSubtypeOf(TypeId.of[Array[Dog]]))
}
```

#### Union and Intersection Types
```scala
test("union type subtyping") {
  // A <: A | B and B <: A | B
  assertTrue(TypeId.of[Int].isSubtypeOf(TypeId.of[Int | String]))
  assertTrue(TypeId.of[String].isSubtypeOf(TypeId.of[Int | String]))

  // A | B <: C requires both A <: C and B <: C
  assertTrue(!TypeId.of[Int | String].isSubtypeOf(TypeId.of[Int]))
}

test("intersection type subtyping") {
  // A & B <: A and A & B <: B
  assertTrue(TypeId.of[Serializable & Comparable[String]].isSubtypeOf(TypeId.of[Serializable]))

  // A <: B & C requires A <: B and A <: C
}
```

#### Nominal Hierarchy Subtyping
```scala
test("class hierarchy subtyping") {
  assertTrue(TypeId.of[Dog].isSubtypeOf(TypeId.of[Animal]))
  assertTrue(TypeId.of[String].isSubtypeOf(TypeId.of[CharSequence]))
}
```

#### Type Alias Transparency
```scala
test("type aliases are transparent for subtyping") {
  type Age = Int
  assertTrue(TypeId.of[Age].isSubtypeOf(TypeId.of[Int]))
  assertTrue(TypeId.of[Int].isSubtypeOf(TypeId.of[Age]))
  assertTrue(TypeId.of[Age].isEquivalentTo(TypeId.of[Int]))
}
```

#### Opaque Type Nominality
```scala
test("opaque types are nominally distinct") {
  opaque type Email = String
  opaque type UserId = String

  assertTrue(!TypeId.of[Email].isSubtypeOf(TypeId.of[String]))  // Outside defining scope
  assertTrue(!TypeId.of[Email].isSubtypeOf(TypeId.of[UserId]))
}
```

