## Acceptance Criteria

- [ ] `TypeId.of[A]` works for all documented type forms on Scala 2.13
- [ ] `TypeId.of[A]` works for all documented type forms on Scala 3.0–3.7
- [ ] `implicit TypeId[A]` derivation works in generic contexts
- [ ] `isSubtypeOf` correctly handles variance, unions, intersections, and nominal hierarchies
- [ ] Type aliases are normalized correctly
- [ ] Opaque types maintain nominal distinction
- [ ] **`equals` and `hashCode` satisfy the Java contract**
- [ ] **`TypeId` works correctly as `Map` and `Set` keys**
- [ ] **Type aliases resolve to equal `TypeId` as their underlying types**
- [ ] **Opaque types have distinct `TypeId` from their representation**
- [ ] **`hashCode` is stable and deterministic across compilations**
- [ ] All tests pass on both Scala versions
- [ ] No runtime reflection is required (all information captured at compile time)

# Sketch of TypeId

# TypeId Data Model for Scala 3.x Type Registry

A comprehensive data model for representing Scala 3 types and type constructors, designed to support:
- Lossless type representation for serialization/deserialization frameworks
- Subtype checking (`isSubtypeOf`)
- Type equality checking
- Type normalization (alias expansion)

## Design Principles

1. **Polykinded phantom types**: `TypeId[A <: AnyKind]` preserves Scala type information at compile time
2. **Separation of identity and representation**: `TypeId` identifies types; `TypeRepr` represents type expressions
3. **Complete metadata**: Capture everything a macro can know at compile time
4. **Stability tracking**: Path-dependent types require knowing path stability

---

## Core Data Model

### Variance
```scala
enum Variance {
  case Invariant
  case Covariant
  case Contravariant

  def symbol: String = this match {
    case Invariant     => ""
    case Covariant     => "+"
    case Contravariant => "-"
  }

  /** Flip variance for contravariant positions */
  def flip: Variance = this match {
    case Invariant     => Invariant
    case Covariant     => Contravariant
    case Contravariant => Covariant
  }
}
```

### TypeBounds
```scala
final case class TypeBounds(
  lower: Option[TypeRepr],  // >: bound
  upper: Option[TypeRepr]   // <: bound
) {
  def isUnbounded: Boolean = lower.isEmpty && upper.isEmpty

  def hasLower: Boolean = lower.isDefined
  def hasUpper: Boolean = upper.isDefined

  /** Combine bounds (intersection of constraints) */
  def &(other: TypeBounds): TypeBounds = TypeBounds(
    lower = (lower, other.lower) match {
      case (Some(l1), Some(l2)) => Some(TypeRepr.Union(l1, l2))
      case (Some(l), None) => Some(l)
      case (None, Some(l)) => Some(l)
      case (None, None) => None
    },
    upper = (upper, other.upper) match {
      case (Some(u1), Some(u2)) => Some(TypeRepr.Intersection(u1, u2))
      case (Some(u), None) => Some(u)
      case (None, Some(u)) => Some(u)
      case (None, None) => None
    }
  )
}

object TypeBounds {
  val empty: TypeBounds = TypeBounds(None, None)

  def upper(tpe: TypeRepr): TypeBounds = TypeBounds(None, Some(tpe))
  def lower(tpe: TypeRepr): TypeBounds = TypeBounds(Some(tpe), None)
  def exact(tpe: TypeRepr): TypeBounds = TypeBounds(Some(tpe), Some(tpe))
}
```

### Kind

Represents the "type of a type" - distinguishing proper types from type constructors.
```scala
sealed trait Kind {
  def arity: Int
  def isProperType: Boolean = this == Kind.Type
  def isHigherKinded: Boolean = !isProperType
}

object Kind {
  /** Proper type: Int, String, List[Int] */
  case object Type extends Kind { 
    def arity: Int = 0 
  }

  /** Type constructor: List, Option, Map */
  final case class Arrow(params: List[Kind], result: Kind) extends Kind {
    def arity: Int = params.size
  }

  // Convenience constructors
  val `* -> *`: Kind = Arrow(List(Type), Type)
  val `* -> * -> *`: Kind = Arrow(List(Type, Type), Type)
  val `(* -> *) -> *`: Kind = Arrow(List(`* -> *`), Type)

  def arity(n: Int): Kind = 
    if (n == 0) Type 
    else Arrow(List.fill(n)(Type), Type)
}
```

### TypeParam

Complete type parameter specification with all information needed for subtyping.
```scala
final case class TypeParam(
  name: String,
  index: Int,
  variance: Variance = Variance.Invariant,
  bounds: TypeBounds = TypeBounds.empty,
  kind: Kind = Kind.Type
) {
  def isHigherKinded: Boolean = kind.isHigherKinded
  def isCovariant: Boolean = variance == Variance.Covariant
  def isContravariant: Boolean = variance == Variance.Contravariant
  def isInvariant: Boolean = variance == Variance.Invariant
}

object TypeParam {
  def invariant(name: String, index: Int): TypeParam = 
    TypeParam(name, index, Variance.Invariant)

  def covariant(name: String, index: Int): TypeParam = 
    TypeParam(name, index, Variance.Covariant)

  def contravariant(name: String, index: Int): TypeParam = 
    TypeParam(name, index, Variance.Contravariant)
}
```

