## Type Definition Classification

### TypeDefKind

Classifies what kind of type definition a `TypeId` represents.
```scala
sealed trait TypeDefKind

object TypeDefKind {
  final case class Class(
    isFinal: Boolean = false,
    isAbstract: Boolean = false,
    isCase: Boolean = false,
    isValue: Boolean = false  // extends AnyVal
  ) extends TypeDefKind

  final case class Trait(
    isSealed: Boolean = false,
    knownSubtypes: List[TypeRepr] = Nil
  ) extends TypeDefKind

  /** Singleton object */
  case object Object extends TypeDefKind

  /** Scala 3 enum */
  final case class Enum(
    cases: List[EnumCaseInfo]
  ) extends TypeDefKind

  /** Individual enum case (when represented as its own type) */
  final case class EnumCase(
    parentEnum: TypeRepr,
    ordinal: Int,
    isObjectCase: Boolean  // case Red vs case RGB(...)
  ) extends TypeDefKind

  /** Type alias: type Foo = Bar */
  case object TypeAlias extends TypeDefKind

  /** Opaque type: opaque type Foo = Bar */
  final case class OpaqueType(
    publicBounds: TypeBounds  // Bounds visible outside defining scope
  ) extends TypeDefKind

  /** Abstract type member */
  case object AbstractType extends TypeDefKind
}

/** Information about an enum case for serialization */
final case class EnumCaseInfo(
  name: String,
  ordinal: Int,
  params: List[EnumCaseParam],  // Empty for object cases
  isObjectCase: Boolean
) {
  def arity: Int = params.size
}

final case class EnumCaseParam(
  name: String,
  tpe: TypeRepr
)
```

