## Type Operations

### Normalization

Expands type aliases to their underlying types.
```scala
object TypeNormalization {

  /**
   * Normalize a type by expanding type aliases.
   * Does NOT expand opaque types (they are nominally distinct).
   */
  def normalize(tpe: TypeRepr): TypeRepr = tpe match {
    // Direct alias reference with no args
    case TypeRepr.Ref(TypeId.Alias(_, _, Nil, aliased)) =>
      normalize(aliased)

    // Applied alias: expand and substitute
    case TypeRepr.Applied(TypeRepr.Ref(TypeId.Alias(_, _, params, aliased)), args) 
        if params.size == args.size =>
      val subs = params.zip(args.map(normalize)).toMap
      normalize(TypeRepr.substitute(aliased, subs))

    // Recurse into compound types
    case TypeRepr.Applied(tycon, args) =>
      TypeRepr.Applied(normalize(tycon), args.map(normalize))

    case TypeRepr.Intersection(comps) =>
      TypeRepr.Intersection(comps.map(normalize))

    case TypeRepr.Union(comps) =>
      TypeRepr.Union(comps.map(normalize))

    case TypeRepr.Function(params, result) =>
      TypeRepr.Function(params.map(normalize), normalize(result))

    case TypeRepr.ContextFunction(params, result) =>
      TypeRepr.ContextFunction(params.map(normalize), normalize(result))

    case TypeRepr.Tuple(elems) =>
      TypeRepr.Tuple(elems.map(e => e.copy(tpe = normalize(e.tpe))))

    case TypeRepr.ByName(u) => TypeRepr.ByName(normalize(u))
    case TypeRepr.Repeated(u) => TypeRepr.Repeated(normalize(u))
    case TypeRepr.Annotated(u, anns) => TypeRepr.Annotated(normalize(u), anns)
    case TypeRepr.Wildcard(bounds) => 
      TypeRepr.Wildcard(TypeBounds(bounds.lower.map(normalize), bounds.upper.map(normalize)))

    // Atoms don't change
    case _ => tpe
  }

  /**
   * Get the underlying representation of an opaque type.
   * Only valid within the opaque type's defining scope.
   */
  def unwrapOpaque(tpe: TypeRepr): Option[TypeRepr] = tpe match {
    case TypeRepr.Ref(TypeId.Opaque(_, _, Nil, repr, _)) =>
      Some(repr)
    case TypeRepr.Applied(TypeRepr.Ref(TypeId.Opaque(_, _, params, repr, _)), args)
        if params.size == args.size =>
      val subs = params.zip(args).toMap
      Some(TypeRepr.substitute(repr, subs))
    case _ => None
  }
}
```

### Type Equality
```scala
object TypeEquality {

  /**
   * Check if two types are equal (after normalization).
   * This is structural equality, not reference equality.
   */
  def areEqual(a: TypeRepr, b: TypeRepr): Boolean = {
    val aNorm = TypeNormalization.normalize(a)
    val bNorm = TypeNormalization.normalize(b)
    structurallyEqual(aNorm, bNorm)
  }

  private def structurallyEqual(a: TypeRepr, b: TypeRepr): Boolean = (a, b) match {
    case (TypeRepr.Ref(idA), TypeRepr.Ref(idB)) =>
      idA.fullName == idB.fullName

    case (TypeRepr.ParamRef(pA, dA), TypeRepr.ParamRef(pB, dB)) =>
      pA.index == pB.index && dA == dB

    case (TypeRepr.Applied(tcA, argsA), TypeRepr.Applied(tcB, argsB)) =>
      structurallyEqual(tcA, tcB) && 
        argsA.size == argsB.size &&
        argsA.zip(argsB).forall { case (x, y) => structurallyEqual(x, y) }

    case (TypeRepr.Intersection(cA), TypeRepr.Intersection(cB)) =>
      cA.size == cB.size && cA.zip(cB).forall { case (x, y) => structurallyEqual(x, y) }

    case (TypeRepr.Union(cA), TypeRepr.Union(cB)) =>
      cA.size == cB.size && cA.zip(cB).forall { case (x, y) => structurallyEqual(x, y) }

    case (TypeRepr.Function(pA, rA), TypeRepr.Function(pB, rB)) =>
      pA.size == pB.size &&
        pA.zip(pB).forall { case (x, y) => structurallyEqual(x, y) } &&
        structurallyEqual(rA, rB)

    case (TypeRepr.Tuple(eA), TypeRepr.Tuple(eB)) =>
      eA.size == eB.size && eA.zip(eB).forall { case (x, y) => 
        x.label == y.label && structurallyEqual(x.tpe, y.tpe)
      }

    case (TypeRepr.ConstantType(cA), TypeRepr.ConstantType(cB)) =>
      cA == cB

    case (TypeRepr.AnyType, TypeRepr.AnyType) => true
    case (TypeRepr.NothingType, TypeRepr.NothingType) => true
    case (TypeRepr.NullType, TypeRepr.NullType) => true
    case (TypeRepr.UnitType, TypeRepr.UnitType) => true

    // More cases for full coverage...
    case _ => false
  }
}
```

### Subtyping
```scala
object Subtyping {

  /**
   * Context for subtyping calculations.
   * Tracks assumptions to handle recursive types and avoid infinite loops.
   */
  final case class Context(
    assumptions: Set[(TypeRepr, TypeRepr)] = Set.empty,
    depth: Int = 0,
    maxDepth: Int = 100
  ) {
    def assume(sub: TypeRepr, sup: TypeRepr): Context =
      copy(assumptions = assumptions + ((sub, sup)))

    def isAssumed(sub: TypeRepr, sup: TypeRepr): Boolean =
      assumptions.contains((sub, sup))

    def deeper: Context = copy(depth = depth + 1)
    def tooDeep: Boolean = depth >= maxDepth
  }

  /**
   * Check if `sub` is a subtype of `sup`.
   * 
   * Implements the Scala 3 subtyping rules including:
   * - Reflexivity: A <: A
   * - Top: A <: Any for all A
   * - Bottom: Nothing <: A for all A  
   * - Variance-aware generic subtyping
   * - Union/intersection type rules
   * - Structural subtyping
   */
  def isSubtype(sub: TypeRepr, sup: TypeRepr)(using ctx: Context = Context()): Boolean = ???

  /**
   * Check if two types are equivalent (mutual subtypes).
   */
  def isEquivalent(a: TypeRepr, b: TypeRepr)(using ctx: Context = Context()): Boolean =
    isSubtype(a, b) && isSubtype(b, a)

  /**
   * Find the least upper bound (LUB) of two types.
   * Returns the most specific type that is a supertype of both.
   */
  def lub(a: TypeRepr, b: TypeRepr): TypeRepr = ???

  /**
   * Find the greatest lower bound (GLB) of two types.
   * Returns the most general type that is a subtype of both.
   */
  def glb(a: TypeRepr, b: TypeRepr): TypeRepr = ???

  /**
   * Check if a type conforms to given bounds.
   */
  def conformsToBounds(tpe: TypeRepr, bounds: TypeBounds)(using ctx: Context = Context()): Boolean = {
    val lowerOk = bounds.lower.forall(lo => isSubtype(lo, tpe))
    val upperOk = bounds.upper.forall(hi => isSubtype(tpe, hi))
    lowerOk && upperOk
  }

  /**
   * Reduce a match type to its result, if possible.
   * Returns None if the match type cannot be reduced (e.g., abstract scrutinee).
   */
  def reduceMatchType(mt: TypeRepr.MatchType)(using ctx: Context = Context()): Option[TypeRepr] = ???
}
